class TownShipModel {  bool? success;  String? message;  List<TownShipData>? data;  TownShipModel({this.success, this.message, this.data});  TownShipModel.fromJson(Map<String, dynamic> json) {    success = json['success'];    message = json['message'];    if (json['data'] != null) {      data = <TownShipData>[];      json['data'].forEach((v) {        data!.add(new TownShipData.fromJson(v));      });    }  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['success'] = this.success;    data['message'] = this.message;    if (this.data != null) {      data['data'] = this.data!.map((v) => v.toJson()).toList();    }    return data;  }}class TownShipData {  int? id;  int? regionId;  String? city;  String? fee;  dynamic? deletedAt;  String? createdAt;  String? updatedAt;  TownShipData(      {this.id,        this.regionId,        this.city,        this.fee,        this.deletedAt,        this.createdAt,        this.updatedAt});  TownShipData.fromJson(Map<String, dynamic> json) {    id = json['id'];    regionId = json['region_id'];    city = json['city'];    fee = json['fee'];    deletedAt = json['deleted_at'];    createdAt = json['created_at'];    updatedAt = json['updated_at'];  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['id'] = this.id;    data['region_id'] = this.regionId;    data['city'] = this.city;    data['fee'] = this.fee;    data['deleted_at'] = this.deletedAt;    data['created_at'] = this.createdAt;    data['updated_at'] = this.updatedAt;    return data;  }}